import { useEffect, useState } from "react";
import { NavBar } from "./NavBar";
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";

export function PocetnaGosti() {
  const [sobe, setSobe] = useState([]);
  const [selectedDatumPrijave, setSelectedDatumPrijave] = useState("");
  const [selectedDatumOdjave, setSelectedDatumOdjave] = useState("");
  const [brojOsoba, setBrojOsoba] = useState(1);

  useEffect(() => {
    fetch("http://localhost:8080/rooms/all")
      .then(res => res.json())
      .then(data => {
        if (data?.data?.values) setSobe(data.data.values);
      });
  }, []);

  const kreirajRezervaciju = async (soba) => {
    const guestId = parseInt(document.cookie.split('userId=')[1]);

    const rezervacijaDTO = {
      datumPrijave: selectedDatumPrijave,
      datumOdjave: selectedDatumOdjave,
      brojOsoba: brojOsoba,
      ukupanIznos: soba.tipSobe?.cenaPoNoci * Math.max(1, getDaysDiff(selectedDatumPrijave, selectedDatumOdjave)),
      statusRezervacije: "PENDING",
      gost: { idGost: guestId },
      soba: { idSoba: soba.idSoba },
      recepcionar: null
    };

    try {
      const response = await fetch("http://localhost:8080/reservations/add", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(rezervacijaDTO)
      });

      if (response.ok) alert("Zahtev za rezervaciju je poslat recepcionaru!");
      else alert("Neuspešno slanje zahteva!");
    } catch (error) {
      console.error(error);
      alert("Server nije dostupan.");
    }
  };

  const getDaysDiff = (start, end) => {
    const d1 = new Date(start);
    const d2 = new Date(end);
    return Math.ceil((d2 - d1) / (1000*60*60*24));
  }

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
      <NavBar />
      <div style={{
        backgroundImage: `url(${pattern})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
        minHeight: "100vh",
        padding: "40px"
      }}>
        <h2 style={{
          textAlign: "center",
          color: "white",
          backgroundColor: "rgba(0,0,0,0.6)",
          padding: "15px",
          borderRadius: "10px",
        }}>Sobe</h2>

        <div style={{ display: "flex", flexWrap: "wrap", justifyContent: "center", gap: "20px", marginTop: "30px" }}>
          {sobe.map(soba => (
            <div key={soba.idSoba} style={{
              width: "250px",
              borderRadius: "15px",
              padding: "15px",
              backgroundColor: "white",
              textAlign: "center"
            }}>
              {soba.slika && <img src={`http://localhost:8080/uploads/${soba.slika.split("/").pop()}`} alt="Slika sobe" style={{ width: "100%", height: "150px", objectFit: "cover", borderRadius: "10px" }} />}
              <h3>{soba.naziv}</h3>
              <p>Tip sobe: {soba.tipSobe?.naziv}</p>
              <p>Cena po noći: {soba.tipSobe?.cenaPoNoci} RSD</p>
              <button onClick={() => kreirajRezervaciju(soba)} style={{ marginTop: "10px" }}>Zahtevaj rezervaciju</button>
            </div>
          ))}
        </div>
      </div>
      <Footer />
    </div>
  );
}
